mapper.select:
SELECT /* 입고의뢰번호 WAREHOUSE_ITEM.WI_WIR_NO와 WH_IN_RPT.WIR_NO를 조인해서 가져온다. 보세재고조회 화면 첫 번째 컬럼에 표시할 값이다. */ WIR.WIR_NO AS "wirNo",
/* 화주명 검색 전 전체조회에서도 검색 결과와 같은 형태로 내려준다. 오른쪽 검색 결과 리스트에서 화주명을 표시할 때 사용한다. */ WIR.WIR_OWR_NM AS "wirOwrNm",
/* 창고물품 기본 정보 */ WI.WI_GG_NO AS "wiGgNo", WI.WIL_CL_NO AS "wilClNo", WI.WI_CG_NO AS "wiCgNo", WI.WI_STATUS_CD AS "wiStatusCd", CC_STATUS.CC_NM AS "wiStatusNm",
/* 3D 화면 표시용 상태
- 반출요청이 없으면 입고완료 - 반출요청이 있고 아직 반출완료일시가 없으면 반출대기
releaseStatusCd / releaseStatusNm: 반출요청 상태 원본에 가까운 값
displayStatusNm: 3D 상세 패널에서 최종적으로 보여줄 상태명 */ CRR3D.RELEASE_STATUS_CD AS "releaseStatusCd", CRR3D.RELEASE_STATUS_NM AS "releaseStatusNm",
CASE WHEN CRR3D.RELEASE_STATUS_CD = 'REL_WAIT' THEN '반출대기' ELSE '입고완료' END AS "displayStatusNm",
/* 위치 정보 */ WIL.WIL_NO AS "locationCode", WIL.WIL_WH_ZONE_NO AS "wilWhZoneNo", WIL.WIL_DESC_CN AS "wilDescCn", TO_CHAR(WIL.WIL_IN_DT, 'YYYY-MM-DD HH24:MI') AS "wilInDt", TO_CHAR(WIL.WIL_OUT_DT, 'YYYY-MM-DD HH24:MI') AS "wilOutDt",
/* 창고 구역 정보 */ WZ.WZ_NM AS "wzNm",
CASE WHEN WZ.WZ_NM LIKE 'A%' THEN 'A' WHEN WZ.WZ_NM LIKE 'B%' THEN 'B' WHEN WZ.WZ_NM LIKE 'C%' THEN 'C' ELSE 'Z' END AS "zone",
/* 물품명 */ GD.GOODS_NAME AS "goodsName",
/* 물품 상세 정보 3D 상세 패널에서 수량, 중량, 원산지를 표시하기 위해 사용한다. CUSTOMS_GOODS는 이미 조인되어 있으므로 새 조인은 필요 없다. */ TO_CHAR(CG.CG_QTY) AS "cgQty", TO_CHAR(CG.CG_WEIGHT) AS "cgWeight", CG.CG_ORIGIN AS "cgOrigin",
/* 수입 / 수출 유형 */ WIR.WIR_IO_SE_CD AS "wirIoSeCd",
CASE WHEN WIR.WIR_IO_SE_CD = 'IMP' THEN '수입' WHEN WIR.WIR_IO_SE_CD = 'EXP' THEN '수출' ELSE WIR.WIR_IO_SE_CD END AS "wirIoSeNm"
FROM WAREHOUSE_ITEM WI
/* 현재 물품 위치 조인 WAREHOUSE_ITEM.WIL_CL_NO = WAREHOUSE_ITEM_LOCATION.WIL_NO */ JOIN WAREHOUSE_ITEM_LOCATION WIL ON WI.WIL_CL_NO = WIL.WIL_NO
/* 창고 구역 조인 */ JOIN WAREHOUSE_ZONE WZ ON WIL.WIL_WH_ZONE_NO = WZ.WZ_NO
/* 통관물품 조인 WI_CG_NO와 WI_GG_NO를 같이 맞춰서 정확한 물품을 찾는다. */ LEFT JOIN CUSTOMS_GOODS CG ON WI.WI_CG_NO = CG.CG_NO AND WI.WI_GG_NO = CG.GG_NO
/* 실제 물품명 조인 */ LEFT JOIN GOODS GD ON CG.GOODS_NO = GD.GOODS_NO
/* 입고의뢰 조인 기존에는 WI_GG_NO = WIR_GG_NO로 조인해서 중복이 발생했다. 이제는 WAREHOUSE_ITEM.WI_WIR_NO = WH_IN_RPT.WIR_NO로 정확히 조인한다. */ LEFT JOIN WH_IN_RPT WIR ON WI.WI_WIR_NO = WIR.WIR_NO
/* 반출요청 상태 조인 */
/* 창고물품 상태명 조인 예: IN_DONE → 입고완료 */ LEFT JOIN COM_CODE CC_STATUS ON WI.WI_STATUS_CD = CC_STATUS.CC_CD AND CC_STATUS.CC_CCG_ID = 'WH_IN_STATUS'
WHERE WI.WI_USE_YN = 'Y' AND WIL.WIL_NO IS NOT NULL AND WZ.WM_ID = #{wmId}
ORDER BY WIL.WIL_NO

SELECT WZ.WZ_NO AS "wzNo", WZ.WZ_WH_NO AS "wzWhNo", WZ.WM_ID AS "wmId", WZ.WZ_NM AS "wzNm", WZ.WZ_TY_CD AS "wzTyCd", WZ.WZ_STATUS_CD AS "wzStatusCd", WZ.WZ_LOAD_PSBL_YN AS "wzLoadPsblYn",
/* 전체 적재 가능 칸 수. 이 값은 WAREHOUSE_ZONE에 세팅해둔 기준값을 그대로 사용한다. 예: A구역 448칸, B구역 189칸, C구역 336칸 */ WZ.WZ_TTL_CAPA AS "wzTtlCapa",
/* 현재 사용 중인 칸 수. WAREHOUSE_ZONE.WZ_USE_CAPA 저장값을 믿는 게 아니라, 실제 WAREHOUSE_ITEM_LOCATION에 현재 반출되지 않은 위치 개수를 센다. */ ( SELECT COUNT(DISTINCT WI.WIL_CL_NO) FROM WAREHOUSE_ITEM WI INNER JOIN WAREHOUSE_ITEM_LOCATION WIL ON WIL.WIL_NO = WI.WIL_CL_NO WHERE WIL.WIL_WH_ZONE_NO = WZ.WZ_NO AND NVL(WI.WI_USE_YN, 'Y') = 'Y' AND WI.WIL_CL_NO IS NOT NULL ) AS "wzUseCapa",
/* 현재 적재율. 현재 사용 칸 수 / 전체 칸 수 * 100 NULLIF는 전체 칸 수가 0일 때 0으로 나누는 오류를 막기 위한 처리다. */ ROUND( ( ( SELECT COUNT(DISTINCT WI.WIL_CL_NO) FROM WAREHOUSE_ITEM WI INNER JOIN WAREHOUSE_ITEM_LOCATION WIL ON WIL.WIL_NO = WI.WIL_CL_NO WHERE WIL.WIL_WH_ZONE_NO = WZ.WZ_NO AND NVL(WI.WI_USE_YN, 'Y') = 'Y' AND WI.WIL_CL_NO IS NOT NULL ) / NULLIF(WZ.WZ_TTL_CAPA, 0) ) * 100, 2 ) AS "wzUseRt",
WZ.WZ_DESC_CN AS "wzDescCn", WZ.WZ_USE_YN AS "wzUseYn", WZ.WZ_REGIST_DT AS "wzRegistDt", WZ.WZ_UPDT_DT AS "wzUpdtDt"
FROM WAREHOUSE_ZONE WZ
WHERE WZ.WZ_USE_YN = 'Y' AND WZ.WZ_STATUS_CD = 'ACTIVE' AND WZ.WM_ID = #{wmId}
ORDER BY WZ.WZ_NO

SELECT COUNT(*) FROM ( /* 1. 현재 보관 중인 재고 - 현재 재고 여부는 WAREHOUSE_ITEM.WI_USE_YN = 'Y' 기준 - 위치반입일시는 물품 row 생성일시인 WI_REGIST_DT 기준 */ SELECT WI.WI_NO AS ITEM_NO FROM WAREHOUSE_ITEM WI
JOIN WAREHOUSE_ITEM_LOCATION WIL ON WI.WIL_CL_NO = WIL.WIL_NO
JOIN WAREHOUSE_ZONE WZ ON WIL.WIL_WH_ZONE_NO = WZ.WZ_NO
LEFT JOIN CUSTOMS_GOODS CG ON WI.WI_CG_NO = CG.CG_NO AND WI.WI_GG_NO = CG.GG_NO
LEFT JOIN GOODS GD ON CG.GOODS_NO = GD.GOODS_NO
LEFT JOIN WH_IN_RPT WIR ON WI.WI_WIR_NO = WIR.WIR_NO
WHERE NVL(WI.WI_USE_YN, 'Y') = 'Y' AND WIL.WIL_NO IS NOT NULL AND WZ.WM_ID = #{wmId}
AND WIL.WIL_WH_ZONE_NO = #{searchDTO.zone}
AND WIR.WIR_IO_SE_CD = #{searchDTO.wirIoSeCd}
AND #{searchDTO.statusCd} = 'IN_DONE'
AND TRUNC(WI.WI_REGIST_DT) >= TO_DATE(#{searchDTO.startDate}, 'YYYY-MM-DD')
AND TRUNC(WI.WI_REGIST_DT) <= TO_DATE(#{searchDTO.endDate}, 'YYYY-MM-DD')
AND ( WIR.WIR_NO LIKE '%' || #{searchDTO.keyword} || '%' OR WIR.WIR_OWR_NM LIKE '%' || #{searchDTO.keyword} || '%' OR GD.GOODS_NAME LIKE '%' || #{searchDTO.keyword} || '%' OR WZ.WZ_NM LIKE '%' || #{searchDTO.keyword} || '%' OR WIL.WIL_WH_ZONE_NO LIKE '%' || #{searchDTO.keyword} || '%' OR WIL.WIL_NO LIKE '%' || #{searchDTO.keyword} || '%' )
UNION ALL
/* 2. 반출완료 이력 - 반출완료 건은 WH_OUT_HIS 기준 - 반출일시는 WOH_OUT_DT 기준 */ SELECT WOH.WOH_WI_NO AS ITEM_NO FROM WH_OUT_HIS WOH
LEFT JOIN WAREHOUSE_ITEM WI ON WI.WI_NO = WOH.WOH_WI_NO
LEFT JOIN WH_IN_RPT WIR ON WI.WI_WIR_NO = WIR.WIR_NO
WHERE WOH.WOH_WM_ID = #{wmId}
AND WOH.WOH_WZ_NO = #{searchDTO.zone}
AND WIR.WIR_IO_SE_CD = #{searchDTO.wirIoSeCd}
AND #{searchDTO.statusCd} = 'REL_DONE'
AND TRUNC(WI.WI_REGIST_DT) >= TO_DATE(#{searchDTO.startDate}, 'YYYY-MM-DD')
AND TRUNC(WI.WI_REGIST_DT) <= TO_DATE(#{searchDTO.endDate}, 'YYYY-MM-DD')
AND ( WIR.WIR_NO LIKE '%' || #{searchDTO.keyword} || '%' OR WOH.WOH_OWR_NM LIKE '%' || #{searchDTO.keyword} || '%' OR WOH.WOH_GOODS_NM LIKE '%' || #{searchDTO.keyword} || '%' OR WOH.WOH_WZ_NM LIKE '%' || #{searchDTO.keyword} || '%' OR WOH.WOH_WZ_NO LIKE '%' || #{searchDTO.keyword} || '%' OR WOH.WOH_LOCATION_CD LIKE '%' || #{searchDTO.keyword} || '%' OR TO_CHAR(WOH.WOH_CRR_NO) LIKE '%' || #{searchDTO.keyword} || '%' )
)

SELECT /* 입고의뢰번호 */ WIR.WIR_NO AS "wirNo",
/* 화주명 3D 검색에서 화주명으로도 찾을 수 있게 내려준다. */ WIR.WIR_OWR_NM AS "wirOwrNm",
/* 창고물품 기본 정보 */ WI.WI_GG_NO AS "wiGgNo", WI.WIL_CL_NO AS "wilClNo", WI.WI_CG_NO AS "wiCgNo", WI.WI_STATUS_CD AS "wiStatusCd", CC_STATUS.CC_NM AS "wiStatusNm",
/* 3D 화면 표시용 상태
- 반출요청이 없으면 입고완료 - 반출요청이 있고 아직 반출완료일시가 없으면 반출대기
releaseStatusCd / releaseStatusNm: 반출요청 상태 원본에 가까운 값
displayStatusNm: 3D 상세 패널에서 최종적으로 보여줄 상태명 */ CRR3D.RELEASE_STATUS_CD AS "releaseStatusCd", CRR3D.RELEASE_STATUS_NM AS "releaseStatusNm",
CASE WHEN CRR3D.RELEASE_STATUS_CD = 'REL_WAIT' THEN '반출대기' ELSE '입고완료' END AS "displayStatusNm",
/* 위치 정보 */ WIL.WIL_NO AS "locationCode", WIL.WIL_WH_ZONE_NO AS "wilWhZoneNo", WIL.WIL_DESC_CN AS "wilDescCn", TO_CHAR(WIL.WIL_IN_DT, 'YYYY-MM-DD HH24:MI') AS "wilInDt", TO_CHAR(WIL.WIL_OUT_DT, 'YYYY-MM-DD HH24:MI') AS "wilOutDt",
/* 창고 구역 정보 */ WZ.WZ_NM AS "wzNm",
CASE WHEN WZ.WZ_NM LIKE 'A%' THEN 'A' WHEN WZ.WZ_NM LIKE 'B%' THEN 'B' WHEN WZ.WZ_NM LIKE 'C%' THEN 'C' ELSE 'Z' END AS "zone",
/* 물품명 */ GD.GOODS_NAME AS "goodsName",
/* 물품 상세 정보 검색 결과에서 선택한 물품의 상세 패널에 표시한다. */ TO_CHAR(CG.CG_QTY) AS "cgQty", TO_CHAR(CG.CG_WEIGHT) AS "cgWeight", CG.CG_ORIGIN AS "cgOrigin",
/* 수입 / 수출 유형 */ WIR.WIR_IO_SE_CD AS "wirIoSeCd",
CASE WHEN WIR.WIR_IO_SE_CD = 'IMP' THEN '수입' WHEN WIR.WIR_IO_SE_CD = 'EXP' THEN '수출' ELSE WIR.WIR_IO_SE_CD END AS "wirIoSeNm"
FROM WAREHOUSE_ITEM WI
JOIN WAREHOUSE_ITEM_LOCATION WIL ON WI.WIL_CL_NO = WIL.WIL_NO
JOIN WAREHOUSE_ZONE WZ ON WIL.WIL_WH_ZONE_NO = WZ.WZ_NO
LEFT JOIN CUSTOMS_GOODS CG ON WI.WI_CG_NO = CG.CG_NO AND WI.WI_GG_NO = CG.GG_NO
LEFT JOIN GOODS GD ON CG.GOODS_NO = GD.GOODS_NO
LEFT JOIN WH_IN_RPT WIR ON WI.WI_WIR_NO = WIR.WIR_NO
/* 반출요청 상태 조인 */
LEFT JOIN COM_CODE CC_STATUS ON WI.WI_STATUS_CD = CC_STATUS.CC_CD AND CC_STATUS.CC_CCG_ID = 'WH_IN_STATUS'
WHERE WI.WI_USE_YN = 'Y' AND WIL.WIL_NO IS NOT NULL AND WZ.WM_ID = #{wmId}
AND ( WIL.WIL_WH_ZONE_NO = #{searchDTO.zone} OR ( CASE WHEN WZ.WZ_NM LIKE 'A%' THEN 'A' WHEN WZ.WZ_NM LIKE 'B%' THEN 'B' WHEN WZ.WZ_NM LIKE 'C%' THEN 'C' ELSE 'Z' END ) = #{searchDTO.zone} )
AND UPPER(WIR.WIR_OWR_NM) LIKE '%' || UPPER(#{searchDTO.keyword}) || '%'
AND UPPER(GD.GOODS_NAME) LIKE '%' || UPPER(#{searchDTO.keyword}) || '%'
AND ( UPPER(WI.WI_CG_NO) LIKE '%' || UPPER(#{searchDTO.keyword}) || '%' OR UPPER(CG.GOODS_NO) LIKE '%' || UPPER(#{searchDTO.keyword}) || '%' )
AND ( UPPER(WIR.WIR_NO) LIKE '%' || UPPER(#{searchDTO.keyword}) || '%' OR UPPER(WIR.WIR_OWR_NM) LIKE '%' || UPPER(#{searchDTO.keyword}) || '%' OR UPPER(GD.GOODS_NAME) LIKE '%' || UPPER(#{searchDTO.keyword}) || '%' OR UPPER(WI.WI_CG_NO) LIKE '%' || UPPER(#{searchDTO.keyword}) || '%' OR UPPER(CG.GOODS_NO) LIKE '%' || UPPER(#{searchDTO.keyword}) || '%' OR UPPER(WZ.WZ_NM) LIKE '%' || UPPER(#{searchDTO.keyword}) || '%' OR UPPER(WIL.WIL_WH_ZONE_NO) LIKE '%' || UPPER(#{searchDTO.keyword}) || '%' OR UPPER(WIL.WIL_NO) LIKE '%' || UPPER(#{searchDTO.keyword}) || '%' )
ORDER BY WIL.WIL_IN_DT DESC NULLS LAST, WIL.WIL_NO
